  RootCause≜{component:String, cause:String, trigger:String}
  Incident≜{id:String, severity:Severity, state:ServiceState, root_cause:RootCause}
  RemediationPlan≜{parallel:[RemediationOp], sequential:[RemediationOp]}
  VerificationResult≜{state:ServiceState, timestamp:Int, confirmed:Bool}
}

⟦Γ:Rules⟧{
  ∀i∈Incident: i.root_cause.trigger≜"missing_eviction_policy"
    → i.root_cause.cause≜"memory_leak"
    → i.root_cause.component≜"cache_layer"
    → i.state≜degraded

  ∀p∈RemediationPlan:
    (p.parallel contains restart_service ∧ p.parallel contains deploy_hotfix)
    ⇒ execute_concurrently(p.parallel)

  execute_concurrently(p.parallel) → completed(p.parallel)
